/**
 * gallery.js
 * Standalone Media Gallery Module for Fancy AI OS
 * Uses IndexedDB (ImageDB) for persistent high-capacity storage.
 */

const GalleryApp = {
    container: null,
    // Touch gesture tracking parameters
    lightboxScale: 1,
    startX: 0,
    startY: 0,
    translateX: 0,
    translateY: 0,
    lastDist: 0,
    lastTap: 0,
    isClosingLightbox: false,

    /**
     * Entry point called by OS.launch
     */
    init: function(container) {
        this.container = container;
        this.render();
        this.loadGalleryGrid();

        // Register popstate listener in the capture phase (true) to intercept before the parent shell can act
        window.removeEventListener('popstate', GalleryApp.handlePopState, true);
        window.addEventListener('popstate', GalleryApp.handlePopState, true);
    },

    render: function() {
        const styleId = "gallery-app-style";
        if (!document.getElementById(styleId)) {
            const style = document.createElement('style');
            style.id = styleId;
            style.innerHTML = `
                .gallery-wrap {
                    padding: 12px;
                    overflow-y: auto;
                    height: 100%;
                    background: #0a0a0b;
                    display: flex;
                    flex-direction: column;
                    gap: 12px;
                    padding-bottom: 100px;
                }
                .gallery-header {
                    display: flex;
                    justify-content: space-between;
                    align-items: center;
                    padding: 4px 6px;
                }
                .gallery-counter {
                    font-size: 0.78rem;
                    color: var(--text-muted);
                    background: var(--bg-card);
                    padding: 4px 10px;
                    border-radius: 10px;
                    border: 1px solid var(--border);
                    font-weight: 600;
                }
                .grid-container {
                    display: grid;
                    grid-template-columns: repeat(3, 1fr);
                    gap: 8px;
                    width: 100%;
                }
                .grid-item {
                    position: relative;
                    aspect-ratio: 1 / 1;
                    background: var(--bg-card);
                    border: 1px solid var(--border);
                    border-radius: 10px;
                    overflow: hidden;
                }
                .grid-item img {
                    width: 100%;
                    height: 100%;
                    object-fit: cover;
                    display: block;
                    cursor: pointer;
                }
                .delete-thumbnail-btn {
                    position: absolute;
                    top: 4px;
                    right: 4px;
                    width: 24px;
                    height: 24px;
                    border-radius: 50%;
                    background: rgba(0, 0, 0, 0.7);
                    color: white;
                    border: none;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    font-size: 14px;
                    z-index: 10;
                }
            `;
            document.head.appendChild(style);
        }

        this.container.innerHTML = `
            <div class="gallery-wrap">
                <div class="gallery-header">
                    <span style="font-weight: 700; font-size: 0.95rem; color: white;">Stored Visuals</span>
                    <span id="galleryGridItemCount" class="gallery-counter">Images: 0</span>
                </div>
                <div id="mediaGridSlot" class="grid-container"></div>
            </div>
        `;
    },

    loadGalleryGrid: async function() {
        const gridSlot = document.getElementById('mediaGridSlot');
        const countBadge = document.getElementById('galleryGridItemCount');
        if (!gridSlot) return;

        gridSlot.innerHTML = `<div style="grid-column: span 3; text-align: center; padding: 40px; color: var(--accent);">Loading Gallery...</div>`;

        try {
            // Wait for DB if it's still initializing
            if (window.ImageDB && typeof window.ImageDB.getAll === 'function') {
                const images = await window.ImageDB.getAll();

                if (!images || images.length === 0) {
                    countBadge.innerText = "Images: 0";
                    gridSlot.innerHTML = `<div style="grid-column: span 3; padding: 60px 20px; text-align: center; color: var(--text-muted); font-size: 0.88rem; font-style: italic;">No images saved yet.</div>`;
                    return;
                }

                countBadge.innerText = `Images: ${images.length}`;
                gridSlot.innerHTML = '';

                // Reverse to show newest first
                [...images].reverse().forEach(img => {
                    const item = document.createElement('div');
                    item.className = 'grid-item';
                    item.innerHTML = `
                        <button class="delete-thumbnail-btn" onclick="event.stopPropagation(); GalleryApp.purgeStoredImage('${img.id}')">✕</button>
                        <img src="${img.data}" alt="Gallery item">
                    `;
                    item.onclick = () => {
                        if (window.ImagingApp) {
                            window.ImagingApp.openLocalLightbox(img.data);
                        }
                    };
                    gridSlot.appendChild(item);
                });
            } else {
                throw new Error("ImageDB not initialized");
            }
        } catch(e) {
            console.error("Gallery Load Error:", e);
            gridSlot.innerHTML = `<div style="grid-column: span 3; text-align: center; color: var(--danger); padding:20px;">Storage Error: ${e.message}</div>`;
        }
    },

    purgeStoredImage: async function(imgId) {
        if (!confirm("Delete this image?")) return;
        try {
            if (window.ImageDB) {
                await window.ImageDB.delete(imgId);
                this.loadGalleryGrid();
            }
        } catch (err) {
            alert("Delete failed: " + err.message);
        }
    },

    handlePopState: function(e) {
        // Placeholder to prevent app exit if lightbox is open (handled by ImagingApp global lightbox)
    }
};

window.GalleryApp = GalleryApp;

/**
 * gallery.js
 * Standalone Media Gallery Module for Fancy AI OS
 * Uses IndexedDB (ImageDB) for persistent high-capacity storage.
 * Features multi-select, select all, and bulk delete.
 */

const GalleryApp = {
    container: null,
    selectedIds: new Set(),
    selectMode: false,
    // Touch gesture tracking parameters
    lightboxScale: 1,
    startX: 0,
    startY: 0,
    translateX: 0,
    translateY: 0,
    lastDist: 0,
    lastTap: 0,
    isClosingLightbox: false,

    /**
     * Entry point called by OS.launch
     */
    init: function(container) {
        this.container = container;
        this.selectedIds = new Set();
        this.selectMode = false;
        this.render();
        this.loadGalleryGrid();

        // Register popstate listener in the capture phase (true) to intercept before the parent shell can act
        window.removeEventListener('popstate', GalleryApp.handlePopState, true);
        window.addEventListener('popstate', GalleryApp.handlePopState, true);
    },

    render: function() {
        const styleId = "gallery-app-style";
        if (!document.getElementById(styleId)) {
            const style = document.createElement('style');
            style.id = styleId;
            style.innerHTML = `
                .gallery-wrap {
                    padding: 12px;
                    overflow-y: auto;
                    height: 100%;
                    background: #0a0a0b;
                    display: flex;
                    flex-direction: column;
                    gap: 12px;
                    padding-bottom: 100px;
                }
                .gallery-header {
                    display: flex;
                    justify-content: space-between;
                    align-items: center;
                    padding: 4px 6px;
                    flex-wrap: wrap;
                    gap: 8px;
                }
                .gallery-header-left {
                    display: flex;
                    align-items: center;
                    gap: 10px;
                }
                .gallery-counter {
                    font-size: 0.78rem;
                    color: var(--text-muted);
                    background: var(--bg-card);
                    padding: 4px 10px;
                    border-radius: 10px;
                    border: 1px solid var(--border);
                    font-weight: 600;
                }
                .gallery-select-btn {
                    background: rgba(139,92,246,0.15);
                    color: var(--accent);
                    border: 1px solid rgba(139,92,246,0.3);
                    padding: 6px 12px;
                    border-radius: 10px;
                    font-size: 0.72rem;
                    font-weight: 700;
                    cursor: pointer;
                    transition: all 0.15s;
                }
                .gallery-select-btn:active { transform: scale(0.94); }
                .gallery-select-btn.active {
                    background: var(--accent);
                    color: white;
                    border-color: var(--accent);
                }
                .gallery-delete-selected-btn {
                    background: rgba(239,68,68,0.15);
                    color: var(--danger);
                    border: 1px solid rgba(239,68,68,0.3);
                    padding: 6px 12px;
                    border-radius: 10px;
                    font-size: 0.72rem;
                    font-weight: 700;
                    cursor: pointer;
                    transition: all 0.15s;
                    display: none;
                }
                .gallery-delete-selected-btn:active { transform: scale(0.94); }
                .gallery-delete-selected-btn.show { display: inline-block; }
                .grid-container {
                    display: grid;
                    grid-template-columns: repeat(3, 1fr);
                    gap: 8px;
                    width: 100%;
                }
                .grid-item {
                    position: relative;
                    aspect-ratio: 1 / 1;
                    background: var(--bg-card);
                    border: 2px solid transparent;
                    border-radius: 10px;
                    overflow: hidden;
                    transition: border-color 0.15s, opacity 0.15s;
                }
                .grid-item.selected {
                    border-color: var(--accent);
                    box-shadow: 0 0 12px rgba(139,92,246,0.3);
                }
                .grid-item img {
                    width: 100%;
                    height: 100%;
                    object-fit: cover;
                    display: block;
                    cursor: pointer;
                }
                .grid-item.selectable img { cursor: default; }
                .delete-thumbnail-btn {
                    position: absolute;
                    top: 4px;
                    right: 4px;
                    width: 24px;
                    height: 24px;
                    border-radius: 50%;
                    background: rgba(0, 0, 0, 0.7);
                    color: white;
                    border: none;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    font-size: 14px;
                    z-index: 10;
                    cursor: pointer;
                }
                .check-overlay {
                    position: absolute;
                    top: 4px;
                    left: 4px;
                    width: 24px;
                    height: 24px;
                    border-radius: 50%;
                    background: rgba(0,0,0,0.6);
                    border: 2px solid rgba(255,255,255,0.3);
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    z-index: 10;
                    font-size: 12px;
                    color: transparent;
                    transition: all 0.15s;
                    pointer-events: none;
                }
                .grid-item.selected .check-overlay {
                    background: var(--accent);
                    border-color: var(--accent);
                    color: white;
                }
                .bulk-bar {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    padding: 8px 6px;
                    border-radius: 12px;
                    background: rgba(139,92,246,0.08);
                    border: 1px solid rgba(139,92,246,0.15);
                    gap: 8px;
                }
                .bulk-count {
                    font-size: 0.82rem;
                    color: var(--text-main);
                    font-weight: 600;
                }
            `;
            document.head.appendChild(style);
        }

        this.container.innerHTML = `
            <div class="gallery-wrap">
                <div class="gallery-header">
                    <div class="gallery-header-left">
                        <span style="font-weight: 700; font-size: 0.95rem; color: white;">Gallery</span>
                        <span id="galleryGridItemCount" class="gallery-counter">Images: 0</span>
                    </div>
                    <div style="display:flex; gap:6px; align-items:center;">
                        <button id="gallerySelectBtn" class="gallery-select-btn" onclick="GalleryApp.toggleSelectMode()">Select</button>
                        <button id="galleryDeleteSelectedBtn" class="gallery-delete-selected-btn" onclick="GalleryApp.bulkDelete()">️ Delete</button>
                    </div>
                </div>
                <div id="galleryBulkBar" class="bulk-bar" style="display:none;">
                    <span id="galleryBulkCount" class="bulk-count">0 selected</span>
                    <div style="display:flex; gap:6px;">
                        <button class="gallery-select-btn" onclick="GalleryApp.selectAll()">Select All</button>
                        <button class="gallery-select-btn" onclick="GalleryApp.deselectAll()">Clear</button>
                    </div>
                </div>
                <div id="mediaGridSlot" class="grid-container"></div>
            </div>
        `;
    },

    toggleSelectMode: function() {
        this.selectMode = !this.selectMode;
        const btn = document.getElementById('gallerySelectBtn');
        const bulkBar = document.getElementById('galleryBulkBar');
        if (this.selectMode) {
            btn.classList.add('active');
            btn.innerText = 'Cancel';
            bulkBar.style.display = 'flex';
        } else {
            btn.classList.remove('active');
            btn.innerText = 'Select';
            bulkBar.style.display = 'none';
            this.deselectAll();
        }
        this.loadGalleryGrid();
    },

    selectAll: function() {
        const gridSlot = document.getElementById('mediaGridSlot');
        if (!gridSlot) return;
        const items = gridSlot.querySelectorAll('.grid-item');
        items.forEach(item => {
            const id = item.dataset.imgId;
            if (id) this.selectedIds.add(id);
            item.classList.add('selected');
        });
        this.updateBulkCount();
        this.updateDeleteBtn();
    },

    deselectAll: function() {
        this.selectedIds.clear();
        const gridSlot = document.getElementById('mediaGridSlot');
        if (gridSlot) {
            gridSlot.querySelectorAll('.grid-item').forEach(item => item.classList.remove('selected'));
        }
        this.updateBulkCount();
        this.updateDeleteBtn();
    },

    toggleSelect: function(imgId) {
        if (this.selectedIds.has(imgId)) {
            this.selectedIds.delete(imgId);
        } else {
            this.selectedIds.add(imgId);
        }
        this.updateBulkCount();
        this.updateDeleteBtn();
        // Update visual state
        const item = document.querySelector(`.grid-item[data-img-id="${imgId}"]`);
        if (item) item.classList.toggle('selected');
    },

    updateBulkCount: function() {
        const el = document.getElementById('galleryBulkCount');
        if (el) el.innerText = `${this.selectedIds.size} selected`;
    },

    updateDeleteBtn: function() {
        const btn = document.getElementById('galleryDeleteSelectedBtn');
        if (btn) {
            btn.classList.toggle('show', this.selectedIds.size > 0);
        }
    },

    bulkDelete: async function() {
        if (this.selectedIds.size === 0) return;
        const count = this.selectedIds.size;
        if (!confirm(`Delete ${count} image${count > 1 ? 's' : ''}?`)) return;
        try {
            for (const id of this.selectedIds) {
                if (window.ImageDB) {
                    await window.ImageDB.delete(id);
                }
            }
            this.selectedIds.clear();
            this.updateBulkCount();
            this.updateDeleteBtn();
            this.loadGalleryGrid();
        } catch (err) {
            alert("Delete failed: " + err.message);
        }
    },

    loadGalleryGrid: async function() {
        const gridSlot = document.getElementById('mediaGridSlot');
        const countBadge = document.getElementById('galleryGridItemCount');
        if (!gridSlot) return;

        gridSlot.innerHTML = `<div style="grid-column: span 3; text-align: center; padding: 40px; color: var(--accent);">Loading Gallery...</div>`;

        try {
            // Wait for DB if it's still initializing
            if (window.ImageDB && typeof window.ImageDB.getAll === 'function') {
                const images = await window.ImageDB.getAll();

                if (!images || images.length === 0) {
                    countBadge.innerText = "Images: 0";
                    gridSlot.innerHTML = `<div style="grid-column: span 3; padding: 60px 20px; text-align: center; color: var(--text-muted); font-size: 0.88rem; font-style: italic;">No images saved yet.</div>`;
                    return;
                }

                countBadge.innerText = `Images: ${images.length}`;
                gridSlot.innerHTML = '';

                // Reverse to show newest first
                [...images].reverse().forEach(img => {
                    const item = document.createElement('div');
                    item.className = 'grid-item' + (this.selectedIds.has(img.id) ? ' selected' : '');
                    item.dataset.imgId = img.id;

                    if (this.selectMode) {
                        item.classList.add('selectable');
                        item.innerHTML = `
                            <div class="check-overlay">${this.selectedIds.has(img.id) ? '✓' : ''}</div>
                            <img src="${img.data}" alt="Gallery item">
                        `;
                        item.onclick = () => this.toggleSelect(img.id);
                    } else {
                        item.innerHTML = `
                            <button class="delete-thumbnail-btn" onclick="event.stopPropagation(); GalleryApp.purgeStoredImage('${img.id}')">✕</button>
                            <img src="${img.data}" alt="Gallery item">
                        `;
                        item.onclick = () => {
                            if (window.ImagingApp) {
                                window.ImagingApp.openLocalLightbox(img.data);
                            }
                        };
                    }
                    gridSlot.appendChild(item);
                });
            } else {
                throw new Error("ImageDB not initialized");
            }
        } catch(e) {
            console.error("Gallery Load Error:", e);
            gridSlot.innerHTML = `<div style="grid-column: span 3; text-align: center; color: var(--danger); padding:20px;">Storage Error: ${e.message}</div>`;
        }
    },

    purgeStoredImage: async function(imgId) {
        if (!confirm("Delete this image?")) return;
        try {
            if (window.ImageDB) {
                await window.ImageDB.delete(imgId);
                this.loadGalleryGrid();
            }
        } catch (err) {
            alert("Delete failed: " + err.message);
        }
    },

    handlePopState: function(e) {
        // Placeholder to prevent app exit if lightbox is open (handled by ImagingApp global lightbox)
    }
};

window.GalleryApp = GalleryApp;

/**
 * settings.js
 * Text LLM Core Configuration & System Maintenance Module
 * Handles system prompts, cloud text providers, and ecosystem data backups.
 */
const SettingsApp = {
    container: null,

    init: function(container) {
        this.container = container;
        this.render();
        this.loadSettingsToForm();
    },

    render: function() {
        const styleId = "settings-app-style";
        if (!document.getElementById(styleId)) {
            const style = document.createElement('style');
            style.id = styleId;
            style.innerHTML = `
                .settings-wrap {
                    padding: 20px;
                    overflow-y: auto;
                    height: 100%;
                    background: #0a0a0b;
                    display: flex;
                    flex-direction: column;
                    gap: 16px;
                    padding-bottom: 100px;
                }
                .form-group {
                    display: flex;
                    flex-direction: column;
                    gap: 6px;
                }
                .form-group label {
                    color: var(--text-muted);
                    font-size: 0.8rem;
                    text-transform: uppercase;
                    letter-spacing: 0.5px;
                    font-weight: 600;
                }
                .form-control {
                    background: var(--bg-input);
                    border: 1px solid var(--border);
                    color: var(--text-main);
                    padding: 12px;
                    border-radius: 10px;
                    font-size: 0.95rem;
                    font-family: inherit;
                    width: 100%;
                    outline: none;
                }
                .form-control:focus { border-color: var(--accent); }
                select.form-control option { background: var(--bg-card); color: var(--text-main); }
                .btn {
                    background: var(--bg-input);
                    color: var(--text-main);
                    border: 1px solid var(--border);
                    padding: 12px 16px;
                    border-radius: 10px;
                    font-weight: 600;
                    cursor: pointer;
                    text-align: center;
                    font-size: 0.95rem;
                    width: 100%;
                }
                .btn:active { transform: scale(0.98); }
                .btn-primary { background: var(--accent); color: white; border: none; }
                hr { border: 0; border-top: 1px solid var(--border); margin: 4px 0; }

                .toggle-group {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    background: var(--bg-card);
                    padding: 12px;
                    border-radius: 10px;
                    border: 1px solid var(--border);
                }
                .switch {
                    position: relative;
                    display: inline-block;
                    width: 46px;
                    height: 24px;
                }
                .switch input { opacity: 0; width: 0; height: 0; }
                .slider {
                    position: absolute;
                    cursor: pointer;
                    top: 0; left: 0; right: 0; bottom: 0;
                    background-color: #333;
                    transition: .4s;
                    border-radius: 24px;
                }
                .slider:before {
                    position: absolute;
                    content: "";
                    height: 18px;
                    width: 18px;
                    left: 3px;
                    bottom: 3px;
                    background-color: white;
                    transition: .4s;
                    border-radius: 50%;
                }
                input:checked + .slider { background-color: var(--accent); }
                input:checked + .slider:before { transform: translateX(22px); }
            `;
            document.head.appendChild(style);
        }

        this.container.innerHTML = `
            <div class="settings-wrap">
                <div class="form-group">
                    <label for="cfgGlobalPrompt">Global System Prompt (Applies to all)</label>
                    <textarea id="cfgGlobalPrompt" class="form-control" rows="3" placeholder="e.g. You are an immersive roleplay AI..."></textarea>
                </div>

                <hr>

                <div style="font-weight: 600; color: var(--text-main); font-size: 0.9rem;">Social Intelligence</div>
                <div class="toggle-group">
                    <div>
                        <div style="font-size: 0.92rem; font-weight: 600;">Autonomous Bot Socials</div>
                        <div style="font-size: 0.75rem; color: var(--text-muted);">Bots will post pix and status to Feed</div>
                    </div>
                    <label class="switch">
                        <input type="checkbox" id="cfgBotSocial">
                        <span class="slider"></span>
                    </label>
                </div>

                <hr>

                <div style="font-weight: 600; color: var(--text-main); font-size: 0.9rem;">Text Generation Engine</div>

                <div class="form-group">
                    <label for="cfgProvider">API Provider</label>
                    <select id="cfgProvider" class="form-control" onchange="SettingsApp.handleProviderChange()">
                        <option value="deepinfra">DeepInfra</option>
                        <option value="openrouter">OpenRouter</option>
                        <option value="custom">Custom OpenAI Endpoint</option>
                    </select>
                </div>
                <div class="form-group">
                    <label for="cfgUrl">Custom Base URL (If Custom selected)</label>
                    <input type="text" id="cfgUrl" class="form-control" placeholder="https://api.custom.com/v1">
                </div>
                <div class="form-group">
                    <label for="cfgKey">API Key</label>
                    <input type="password" id="cfgKey" class="form-control" placeholder="Bearer Token">
                </div>
                <div class="form-group">
                    <label for="cfgModel">Model ID</label>
                    <div style="display: flex; gap: 8px;">
                        <input type="text" id="cfgModel" class="form-control" style="flex: 1;">
                        <button class="btn" style="width: auto; padding: 0 12px;" onclick="SettingsApp.fetchAvailableModels()"></button>
                    </div>
                </div>

                <hr>

                <div style="font-weight: 600; color: var(--text-main); font-size: 0.9rem;">Ecosystem Data Management</div>
                <div style="display: flex; gap: 10px; margin-bottom: 15px;">
                    <button class="btn" onclick="SettingsApp.exportData()" style="flex: 1;"> Export Backup (.zip)</button>
                    <label class="btn" style="flex: 1; cursor: pointer; text-align: center; margin: 0;">
                         Import Backup
                        <input type="file" style="display:none" accept=".zip,.json" onchange="SettingsApp.importData(event)">
                    </label>
                </div>

                <button class="btn btn-primary" onclick="SettingsApp.saveSettings()">Save Configurations</button>
            </div>

            <div id="settingsAppModelModal" style="display:none; position:fixed; top:0; left:0; width:100vw; height:100vh; background:rgba(0,0,0,0.85); z-index:9999; justify-content:center; align-items:center; padding:20px;">
                <div style="background:var(--bg-card); border:1px solid var(--border); width:100%; max-width:400px; border-radius:16px; display:flex; flex-direction:column; max-height:80vh; overflow:hidden;">
                    <div style="display:flex; justify-content:space-between; padding:16px; border-bottom:1px solid var(--border); align-items:center;">
                        <h3 style="margin:0; font-size:1.1rem;">Available Models</h3>
                        <button class="btn" style="width:auto; padding:4px 10px;" onclick="document.getElementById('settingsAppModelModal').style.display='none'">✕</button>
                    </div>
                    <div style="padding:12px 16px; border-bottom:1px solid var(--border);">
                        <input type="text" id="settingsAppModelSearch" class="form-control" placeholder="Search models..." oninput="SettingsApp.filterModelsList()">
                    </div>
                    <div id="settingsAppModelsContainer" style="padding:16px; overflow-y:auto; display:flex; flex-direction:column; gap:8px;"></div>
                </div>
            </div>
        `;
    },

    handleProviderChange: function() {
        const provSel = document.getElementById('cfgProvider');
        const urlInput = document.getElementById('cfgUrl');
        if (provSel.value === 'deepinfra' || provSel.value === 'openrouter') {
            urlInput.value = '';
            urlInput.disabled = true;
        } else {
            urlInput.disabled = false;
            urlInput.placeholder = 'https://api.yourcustom.com/v1/chat/completions';
        }
    },

    loadSettingsToForm: function() {
        if (!State.settings) State.settings = {};
        const s = State.settings;
        document.getElementById('cfgGlobalPrompt').value = s.globalSystemPrompt || '';
        document.getElementById('cfgProvider').value = s.provider || 'deepinfra';
        document.getElementById('cfgUrl').value = s.url || '';
        document.getElementById('cfgKey').value = s.key || '';
        document.getElementById('cfgModel').value = s.model || '';
        document.getElementById('cfgBotSocial').checked = s.enableBotSocial || false;

        this.handleProviderChange();
    },

    saveSettings: function() {
        State.settings.globalSystemPrompt = document.getElementById('cfgGlobalPrompt').value;
        State.settings.provider = document.getElementById('cfgProvider').value;
        State.settings.url = document.getElementById('cfgUrl').value.replace(/\/$/, '');
        State.settings.key = document.getElementById('cfgKey').value;
        State.settings.model = document.getElementById('cfgModel').value;
        State.settings.enableBotSocial = document.getElementById('cfgBotSocial').checked;

        State.save();
        alert("Text infrastructure configurations saved!");
        OS.goHome();
    },

    fetchAvailableModels: async function() {
        const provider = document.getElementById('cfgProvider').value;
        const key = document.getElementById('cfgKey').value || State.settings.key || "";
        const customUrl = document.getElementById('cfgUrl').value || State.settings.url || "";

        const modal = document.getElementById('settingsAppModelModal');
        const container = document.getElementById('settingsAppModelsContainer');
        modal.style.display = 'flex';
        container.innerHTML = `<div class="loading-pulse">Retrieving text profiles from ${provider}...</div>`;

        let url = "";
        let headers = { "Content-Type": "application/json" };

        if (provider === 'openrouter') {
            url = "https://openrouter.ai/api/v1/models";
        } else if (provider === 'deepinfra') {
            url = "https://api.deepinfra.com/v1/openai/models";
            if (key) headers["Authorization"] = `Bearer ${key}`;
        } else {
            if (!customUrl) {
                container.innerHTML = `<span style="color:var(--danger)">Define custom base URL endpoint.</span>`;
                return;
            }
            url = `${customUrl.replace(/\/$/, '')}/models`;
            if (key) headers["Authorization"] = `Bearer ${key}`;
        }

        try {
            const res = await fetch(url, { method: 'GET', headers });
            if (!res.ok) throw new Error(`HTTP ${res.status}`);
            const data = await res.json();

            let models = [];
            if (Array.isArray(data.data)) {
                models = data.data.map(m => ({ id: m.id, name: m.name || m.id }));
            } else if (Array.isArray(data)) {
                models = data.map(m => ({ id: m.id || m, name: m.name || m.id || m }));
            }

            State.fetchedModels = models;
            this.renderModelsList(models);
        } catch(e) {
            container.innerHTML = `<span style="color:var(--danger)">Error: ${e.message}</span>`;
        }
    },

    renderModelsList: function(models) {
        const container = document.getElementById('settingsAppModelsContainer');
        container.innerHTML = "";
        models.forEach(m => {
            const item = document.createElement('div');
            item.style = "cursor: pointer; padding: 12px; border:1px solid var(--border); border-radius:8px;";
            item.innerHTML = `<div style="font-weight:600; color:white;">${m.name}</div><div style="font-family:monospace; font-size:0.75rem; color:var(--text-muted);">${m.id}</div>`;
            item.onclick = () => {
                document.getElementById('cfgModel').value = m.id;
                State.settings.model = m.id;
                State.save();
                document.getElementById('settingsAppModelModal').style.display = 'none';
            };
            container.appendChild(item);
        });
    },

    filterModelsList: function() {
        const q = document.getElementById('settingsAppModelSearch').value.toLowerCase().trim();
        if (!State.fetchedModels) return;
        const filtered = State.fetchedModels.filter(m => m.name.toLowerCase().includes(q) || m.id.toLowerCase().includes(q));
        this.renderModelsList(filtered);
    },

    exportData: async function() {
        try {
            if (typeof JSZip === 'undefined') {
                await new Promise((resolve, reject) => {
                    const script = document.createElement('script');
                    script.src = "https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js";
                    script.onload = resolve; script.onerror = reject; document.head.appendChild(script);
                });
            }

            // Collect entire state
            const data = {
                settings: State.settings,
                chars: State.characters,
                activeChar: State.activeCharId,
                sessions: State.sessions,
                feedPosts: State.feedPosts || []
            };

            const zip = new JSZip();
            zip.file('backup.json', JSON.stringify(data));

            // Include Gallery Images from IndexedDB
            let images = [];
            if (window.ImageDB && typeof window.ImageDB.getAll === 'function') {
                images = await window.ImageDB.getAll();
            }

            if (images && images.length > 0) {
                const imgFolder = zip.folder('images');
                images.forEach(img => {
                    // Store as .txt or .png if we can parse b64 easily
                    imgFolder.file(`${img.id}.txt`, img.data);
                });
            }

            const blob = await zip.generateAsync({
                type: 'blob',
                mimeType: 'application/zip',
                compression: 'DEFLATE'
            });

            const reader = new FileReader();
            reader.onload = function() {
                // reader.result is a data:application/zip;base64,...
                if (window.AndroidBridge && typeof window.AndroidBridge.exportBackup === 'function') {
                    window.AndroidBridge.exportBackup(reader.result);
                } else {
                    const a = document.createElement('a');
                    a.href = reader.result;
                    a.download = `fancy_ai_backup_${Date.now()}.zip`;
                    document.body.appendChild(a);
                    a.click();
                    document.body.removeChild(a);
                }
            };
            reader.readAsDataURL(blob);
        } catch(e) {
            console.error("Export Error:", e);
            alert("Export failed: " + e.message);
        }
    },

    importData: function(event) {
        const file = event.target.files[0];
        if(!file) return;
        const reader = new FileReader();
        reader.onload = async (e) => {
            try {
                if (file.name.endsWith('.zip')) {
                    if (typeof JSZip === 'undefined') {
                        await new Promise((resolve, reject) => {
                            const script = document.createElement('script');
                            script.src = "https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js";
                            script.onload = resolve; script.onerror = reject; document.head.appendChild(script);
                        });
                    }
                    const zip = await JSZip.loadAsync(e.target.result);
                    const backupFile = zip.file('backup.json');
                    if (!backupFile) throw new Error('Invalid Backup: Missing backup.json');

                    const data = JSON.parse(await backupFile.async('text'));

                    // Restore State
                    if (data.settings) State.settings = data.settings;
                    if (data.chars) State.characters = data.chars;
                    if (data.activeChar) State.activeCharId = data.activeChar;
                    if (data.sessions) State.sessions = data.sessions;
                    if (data.feedPosts) State.feedPosts = data.feedPosts;

                    State.save();

                    // Restore Images
                    const imgFolder = zip.folder('images');
                    if (imgFolder && window.ImageDB) {
                        const files = imgFolder.file(/.*/);
                        for (const f of files) {
                            const id = f.name.replace('images/', '').replace('.txt', '');
                            const content = await f.async('text');
                            await window.ImageDB.save(id, content);
                        }
                    }
                } else {
                    // Legacy JSON support
                    const data = JSON.parse(e.target.result);
                    Object.assign(State, data);
                    State.save();
                }
                alert("Import Successful! System will reload.");
                location.reload();
            } catch(err) { 
                console.error("Import Error:", err);
                alert("Import Failed: " + err.message); 
            }
        };
        if (file.name.endsWith('.zip')) { reader.readAsArrayBuffer(file); } else { reader.readAsText(file); }
    }
};

window.SettingsApp = SettingsApp;

/**
 * settings.js
 * Text LLM Core Configuration & System Maintenance Module
 * Handles system prompts, cloud text providers, and ecosystem data backups.
 */
const SettingsApp = {
    container: null,

    init: function(container) {
        this.container = container;
        this.render();
        this.loadSettingsToForm();
    },

    render: function() {
        const styleId = "settings-app-style";
        if (!document.getElementById(styleId)) {
            const style = document.createElement('style');
            style.id = styleId;
            style.innerHTML = `
                .settings-wrap {
                    padding: 20px;
                    overflow-y: auto;
                    height: 100%;
                    background: #0a0a0b;
                    display: flex;
                    flex-direction: column;
                    gap: 16px;
